/**
 * FreshBooks API Service
 * Handles communication with the FreshBooks API, including authentication
 * and fetching invoice data.
 */

const https = require('https');
require('dotenv').config();

// FreshBooks API base URL
const FRESHBOOKS_API_BASE = 'https://api.freshbooks.com';

/**
 * Retrieves the FreshBooks account ID from environment variables.
 * @returns {string} The account ID.
 * @throws {Error} If the account ID is not configured.
 */
function getAccountId() {
  const accountId = process.env.FRESHBOOKS_ACCOUNT_ID;
  if (!accountId) {
    throw new Error('FRESHBOOKS_ACCOUNT_ID is not configured in environment variables.');
  }
  return accountId;
}

/**
 * Retrieves the FreshBooks access token from environment variables.
 * @returns {string} The access token.
 * @throws {Error} If the access token is not configured.
 */
function getAccessToken() {
  const token = process.env.FRESHBOOKS_ACCESS_TOKEN;
  if (!token) {
    throw new Error('FRESHBOOKS_ACCESS_TOKEN is not configured in environment variables.');
  }
  return token;
}

/**
 * Makes an authenticated HTTP GET request to the FreshBooks API.
 * @param {string} path - The API path to request.
 * @returns {Promise<object>} The parsed JSON response.
 */
function makeApiRequest(path) {
  return new Promise((resolve, reject) => {
    const accessToken = getAccessToken();
    const url = `${FRESHBOOKS_API_BASE}${path}`;

    const options = {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
        'Api-Version': 'alpha',
      },
    };

    const req = https.request(url, options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);

          // Handle HTTP-level errors from FreshBooks
          if (res.statusCode === 401) {
            return reject(new Error('FreshBooks authentication failed. Check your access token.'));
          }

          if (res.statusCode === 403) {
            return reject(new Error('FreshBooks authorization error. Insufficient permissions.'));
          }

          if (res.statusCode === 404) {
            return reject(new Error(`FreshBooks resource not found: ${path}`));
          }

          if (res.statusCode === 429) {
            return reject(new Error('FreshBooks API rate limit exceeded. Please try again later.'));
          }

          if (res.statusCode >= 500) {
            return reject(new Error(`FreshBooks server error (${res.statusCode}). Please try again later.`));
          }

          if (res.statusCode < 200 || res.statusCode >= 300) {
            return reject(new Error(`Unexpected FreshBooks API response: HTTP ${res.statusCode}`));
          }

          resolve(parsed);
        } catch (parseError) {
          reject(new Error(`Failed to parse FreshBooks API response: ${parseError.message}`));
        }
      });
    });

    req.on('error', (networkError) => {
      reject(new Error(`Network error communicating with FreshBooks: ${networkError.message}`));
    });

    // Set a timeout to avoid hanging requests
    req.setTimeout(10000, () => {
      req.destroy();
      reject(new Error('FreshBooks API request timed out after 10 seconds.'));
    });

    req.end();
  });
}

/**
 * Normalizes a raw FreshBooks invoice object into a consistent format
 * suitable for the application UI.
 * @param {object} invoice - Raw invoice object from FreshBooks API.
 * @returns {object} Normalized invoice object.
 */
function normalizeInvoice(invoice) {
  return {
    id: invoice.id || invoice.invoiceid,
    invoiceNumber: invoice.invoice_number || invoice.number || '',
    status: invoice.v3_status || invoice.status || 'unknown',
    clientId: invoice.customerid || invoice.client_id || null,
    clientName: invoice.current_organization || invoice.client_name || 'Unknown Client',
    amount: {
      total: invoice.amount ? invoice.amount.amount : '0.00',
      currency: invoice.amount ? invoice.amount.code : 'USD',
    },
    amountOutstanding: {
      total: invoice.outstanding ? invoice.outstanding.amount : '0.00',
      currency: invoice.outstanding ? invoice.outstanding.code : 'USD',
    },
    createdAt: invoice.create_date || invoice.created_at || null,
    dueDate: invoice.due_date || null,
    description: invoice.description || '',
    lines: Array.isArray(invoice.lines) ? invoice.lines.map((line) => ({
      id: line.lineid,
      description: line.description || '',
      quantity: line.qty || 0,
      unitCost: line.unit_cost ? line.unit_cost.amount : '0.00',
      amount: line.amount ? line.amount.amount : '0.00',
    })) : [],
  };
}

/**
 * Fetches invoice data from the FreshBooks API.
 * Retrieves all invoices for the configured account, normalized for UI consumption.
 *
 * @returns {Promise<object>} An object containing the list of invoices and metadata.
 * @throws {Error} On network errors, authentication failures, or unexpected API responses.
 *
 * @example
 * const { invoices, total } = await fetchInvoices();
 */
async function fetchInvoices() {
  const accountId = getAccountId();
  const path = `/accounting/account/${accountId}/invoices/invoices`;

  const response = await makeApiRequest(path);

  // Validate the expected response structure
  if (!response || !response.response) {
    throw new Error('Unexpected FreshBooks API response structure: missing response object.');
  }

  const result = response.response.result;

  if (!result || !result.invoices) {
    // Return empty list if no invoices found rather than throwing
    return {
      invoices: [],
      total: 0,
      pages: 0,
      perPage: 0,
      page: 1,
    };
  }

  const normalizedInvoices = result.invoices.map(normalizeInvoice);

  return {
    invoices: normalizedInvoices,
    total: result.total || normalizedInvoices.length,
    pages: result.pages || 1,
    perPage: result.per_page || normalizedInvoices.length,
    page: result.page || 1,
  };
}

module.exports = {
  fetchInvoices,
  // Export internals for unit testing
  normalizeInvoice,
  makeApiRequest,
};

/**
 * Finance Controller
 * Handles HTTP requests related to financial data, including invoices.
 * Delegates data fetching to the appropriate service layer.
 */

const { fetchInvoices } = require('../services/freshBooksApi');

/**
 * GET /api/invoices
 * Retrieves invoice data from FreshBooks and returns it as JSON.
 *
 * @param {import('express').Request} req - Express request object.
 * @param {import('express').Response} res - Express response object.
 * @returns {Promise<void>}
 *
 * Success Response (200):
 * {
 *   success: true,
 *   data: {
 *     invoices: [...],
 *     total: number,
 *     pages: number,
 *     perPage: number,
 *     page: number
 *   }
 * }
 *
 * Error Response (4xx/5xx):
 * {
 *   success: false,
 *   error: string,
 *   code: string
 * }
 */
async function getInvoices(req, res) {
  try {
    const invoiceData = await fetchInvoices();

    return res.status(200).json({
      success: true,
      data: invoiceData,
    });
  } catch (error) {
    console.error('[financeController] Error fetching invoices:', error.message);

    // Determine the appropriate HTTP status code based on the error type
    if (
      error.message.includes('authentication failed') ||
      error.message.includes('access token')
    ) {
      return res.status(401).json({
        success: false,
        error: 'Authentication with FreshBooks failed. Please check your API credentials.',
        code: 'FRESHBOOKS_AUTH_ERROR',
      });
    }

    if (error.message.includes('authorization error') || error.message.includes('permissions')) {
      return res.status(403).json({
        success: false,
        error: 'Insufficient permissions to access FreshBooks invoice data.',
        code: 'FRESHBOOKS_PERMISSION_ERROR',
      });
    }

    if (error.message.includes('not configured')) {
      return res.status(500).json({
        success: false,
        error: 'FreshBooks API is not properly configured on the server.',
        code: 'FRESHBOOKS_CONFIG_ERROR',
      });
    }

    if (error.message.includes('rate limit')) {
      return res.status(429).json({
        success: false,
        error: 'FreshBooks API rate limit exceeded. Please try again later.',
        code: 'FRESHBOOKS_RATE_LIMIT',
      });
    }

    if (error.message.includes('timed out')) {
      return res.status(504).json({
        success: false,
        error: 'Request to FreshBooks API timed out. Please try again.',
        code: 'FRESHBOOKS_TIMEOUT',
      });
    }

    if (error.message.includes('Network error')) {
      return res.status(502).json({
        success: false,
        error: 'Unable to connect to FreshBooks API. Please check your network connection.',
        code: 'FRESHBOOKS_NETWORK_ERROR',
      });
    }

    // Generic server error fallback
    return res.status(500).json({
      success: false,
      error: 'An unexpected error occurred while fetching invoice data.',
      code: 'INTERNAL_SERVER_ERROR',
    });
  }
}

module.exports = {
  getInvoices,
};

/**
 * Unit Tests: FreshBooks API Service
 * Tests the fetchInvoices() function and supporting utilities
 * using mocked HTTP responses to simulate FreshBooks API behavior.
 */

// Mock the https module before requiring the service
jest.mock('https');

const https = require('https');
const { fetchInvoices, normalizeInvoice } = require('../../server/services/freshBooksApi');

// ─── Helpers ────────────────────────────────────────────────────────────────

/**
 * Creates a mock https.request that simulates a FreshBooks API response.
 * @param {number} statusCode - HTTP status code to simulate.
 * @param {object|string} body - Response body (object will be JSON-stringified).
 * @param {Error|null} requestError - Optional error to emit on the request.
 * @param {boolean} timeout - Whether to simulate a timeout.
 */
function mockHttpsRequest(statusCode, body, requestError = null, timeout = false) {
  const responseData = typeof body === 'string' ? body : JSON.stringify(body);

  const mockResponse = {
    statusCode,
    on: jest.fn((event, handler) => {
      if (event === 'data') handler(responseData);
      if (event === 'end') handler();
    }),
  };

  const mockRequest = {
    on: jest.fn((event, handler) => {
      if (event === 'error' && requestError) handler(requestError);
    }),
    setTimeout: jest.fn((ms, handler) => {
      if (timeout) handler();
    }),
    destroy: jest.fn(),
    end: jest.fn(),
  };

  https.request.mockImplementation((url, options, callback) => {
    if (!requestError && !timeout) {
      callback(mockResponse);
    }
    return mockRequest;
  });

  return { mockRequest, mockResponse };
}

// ─── Environment Setup ───────────────────────────────────────────────────────

beforeEach(() => {
  jest.clearAllMocks();
  process.env.FRESHBOOKS_ACCESS_TOKEN = 'test-access-token';
  process.env.FRESHBOOKS_ACCOUNT_ID = 'test-account-id';
});

afterEach(() => {
  delete process.env.FRESHBOOKS_ACCESS_TOKEN;
  delete process.env.FRESHBOOKS_ACCOUNT_ID;
});

// ─── fetchInvoices() Tests ───────────────────────────────────────────────────

describe('fetchInvoices()', () => {
  const mockApiResponse = {
    response: {
      result: {
        invoices: [
          {
            id: 1001,
            invoice_number: 'INV-001',
            v3_status: 'paid',
            customerid: 42,
            current_organization: 'Acme Corp',
            amount: { amount: '1500.00', code: 'USD' },
            outstanding: { amount: '0.00', code: 'USD' },
            create_date: '2024-01-15',
            due_date: '2024-02-15',
            description: 'Web development services',
            lines: [
              {
                lineid: 1,
                description: 'Frontend development',
                qty: 10,
                unit_cost: { amount: '150.00' },
                amount: { amount: '1500.00' },
              },
            ],
          },
          {
            id: 1002,
            invoice_number: 'INV-002',
            v3_status: 'sent',
            customerid: 43,
            current_organization: 'Beta LLC',
            amount: { amount: '800.00', code: 'USD' },
            outstanding: { amount: '800.00', code: 'USD' },
            create_date: '2024-02-01',
            due_date: '2024-03-01',
            description: 'Consulting',
            lines: [],
          },
        ],
        total: 2,
        pages: 1,
        per_page: 15,
        page: 1,
      },
    },
  };

  test('returns normalized invoice data on success', async () => {
    mockHttpsRequest(200, mockApiResponse);

    const result = await fetchInvoices();

    expect(result).toHaveProperty('invoices');
    expect(result.invoices).toHaveLength(2);
    expect(result.total).toBe(2);
    expect(result.pages).toBe(1);

    const first = result.invoices[0];
    expect(first.id).toBe(1001);
    expect(first.invoiceNumber).toBe('INV-001');
    expect(first.status).toBe('paid');
    expect(first.clientName).toBe('Acme Corp');
    expect(first.amount.total).toBe('1500.00');
    expect(first.amount.currency).toBe('USD');
    expect(first.lines).toHaveLength(1);
    expect(first.lines[0].description).toBe('Frontend development');
  });

  test('returns empty invoices array when result has no invoices', async () => {
    mockHttpsRequest(200, {
      response: {
        result: {},
      },
    });

    const result = await fetchInvoices();

    expect(result.invoices).toEqual([]);
    expect(result.total).toBe(0);
  });

  test('throws authentication error on 401 response', async () => {
    mockHttpsRequest(401, { error: 'Unauthorized' });

    await expect(fetchInvoices()).rejects.toThrow('authentication failed');
  });

  test('throws authorization error on 403 response', async () => {
    mockHttpsRequest(403, { error: 'Forbidden' });

    await expect(fetchInvoices()).rejects.toThrow('authorization error');
  });

  test('throws not found error on 404 response', async () => {
    mockHttpsRequest(404, { error: 'Not Found' });

    await expect(fetchInvoices()).rejects.toThrow('not found');
  });

  test('throws rate limit error on 429 response', async () => {
    mockHttpsRequest(429, { error: 'Too Many Requests' });

    await expect(fetchInvoices()).rejects.toThrow('rate limit');
  });

  test('throws server error on 500 response', async () => {
    mockHttpsRequest(500, { error: 'Internal Server Error' });

    await expect(fetchInvoices()).rejects.toThrow('server error');
  });

  test('throws network error when request fails', async () => {
    mockHttpsRequest(null, null, new Error('ECONNREFUSED'));

    // Re-mock to emit error on request
    const mockRequest = {
      on: jest.fn((event, handler) => {
        if (event === 'error') handler(new Error('ECONNREFUSED'));
      }),
      setTimeout: jest.fn(),
      destroy: jest.fn(),
      end: jest.fn(),
    };
    https.request.mockImplementation(() => mockRequest);

    await expect(fetchInvoices()).rejects.toThrow('Network error');
  });

  test('throws timeout error when request times out', async () => {
    const mockRequest = {
      on: jest.fn(),
      setTimeout: jest.fn((ms, handler) => handler()), // immediately trigger timeout
      destroy: jest.fn(),
      end: jest.fn(),
    };
    https.request.mockImplementation(() => mockRequest);

    await expect(fetchInvoices()).rejects.toThrow('timed out');
  });

  test('throws config error when access token is missing', async () => {
    delete process.env.FRESHBOOKS_ACCESS_TOKEN;

    await expect(fetchInvoices()).rejects.toThrow('FRESHBOOKS_ACCESS_TOKEN');
  });

  test('throws config error when account ID is missing', async () => {
    delete process.env.FRESHBOOKS_ACCOUNT_ID;

    await expect(fetchInvoices()).rejects.toThrow('FRESHBOOKS_ACCOUNT_ID');
  });

  test('throws parse error on malformed JSON response', async () => {
    mockHttpsRequest(200, 'not valid json {{{}');

    await expect(fetchInvoices()).rejects.toThrow('Failed to parse');
  });

  test('throws error on unexpected response structure', async () => {
    mockHttpsRequest(200, { unexpected: 'structure' });

    await expect(fetchInvoices()).rejects.toThrow('Unexpected FreshBooks API response structure');
  });
});

// ─── normalizeInvoice() Tests ────────────────────────────────────────────────

describe('normalizeInvoice()', () => {
  test('normalizes a complete invoice object', () => {
    const raw = {
      id: 999,
      invoice_number: 'INV-999',
      v3_status: 'draft',
      customerid: 10,
      current_organization: 'Test Co',
      amount: { amount: '500.00', code: 'CAD' },
      outstanding: { amount: '500.00', code: 'CAD' },
      create_date: '2024-03-01',
      due_date: '2024-04-01',
      description: 'Test invoice',
      lines: [
        {
          lineid: 5,
          description: 'Item A',
          qty: 2,
          unit_cost: { amount: '250.00' },
          amount: { amount: '500.00' },
        },
      ],
    };

    const normalized = normalizeInvoice(raw);

    expect(normalized.id).toBe(999);
    expect(normalized.invoiceNumber).toBe('INV-999');
    expect(normalized.status).toBe('draft');
    expect(normalized.clientId).toBe(10);
    expect(normalized.clientName).toBe('Test Co');
    expect(normalized.amount.total).toBe('500.00');
    expect(normalized.amount.currency).toBe('CAD');
    expect(normalized.lines).toHaveLength(1);
    expect(normalized.lines[0].id).toBe(5);
    expect(normalized.lines[0].quantity).toBe(2);
  });

  test('handles missing optional fields gracefully', () => {
    const raw = { id: 1 };
    const normalized = normalizeInvoice(raw);

    expect(normalized.id).toBe(1);
    expect(normalized.invoiceNumber).toBe('');
    expect(normalized.status).toBe('unknown');
    expect(normalized.clientName).toBe('Unknown Client');
    expect(normalized.amount.total).toBe('0.00');
    expect(normalized.amount.currency).toBe('USD');
    expect(normalized.lines).toEqual([]);
  });

  test('falls back to invoiceid when id is not present', () => {
    const raw = { invoiceid: 777 };
    const normalized = normalizeInvoice(raw);
    expect(normalized.id).toBe(777);
  });
});
